VALUES
  ('elementary-f29af906-moex-00188', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依訴願法規定，下列何種情形，訴願審議委員會應為不受理之決定？', '["對土地鑑界複丈結果收到通知後，表示不服而提起訴願", "對土地權狀補發登記申請收到駁回通知後，表示不服而提起訴願", "對土地權狀換發登記申請收到駁回通知後，表示不服而提起訴願", "對土地申請抵押權登記收到駁回通知後，表示不服而提起訴願"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00189', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '經營不動產仲介業務者，對於代理成交之租賃案件，應於簽訂租賃契約書之日起30日內，向直轄市、縣 （市）政府主管機關申報登錄成交案件實際資訊。假設A直轄市政府地政局將前項申報登錄租賃案件實 際資訊業務及相關裁罰事項之管轄權，委任所轄B地政事務所辦理；B地政事務所對資訊申報不實之C 不動產仲介業者，依法作出裁罰處分。關於前述情形，下列敘述何者正確？', '["B地政事務所依法所作之裁罰處分仍屬A直轄市政府地政局之行政處分", "C對該裁罰處分不服提起訴願，B地政事務所為訴願管轄機關", "B地政事務所依法所作之裁罰處分為該所之行政處分", "C對該裁罰處分不服提起訴願，A直轄市政府地政局為訴願管轄機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00190', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '人民因行政機關對其依法申請之案件，予以駁回，經訴願程序後，應提起何種行政訴訟？', '["撤銷訴訟", "確認訴訟", "課予義務訴訟", "一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00191', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '甲於開放之自然山域健行，行走於設有「小心落石」警告標示之木棧道時，因落石而致傷害；有關甲擬請 求國家賠償，下列敘述何者錯誤？', '["木棧道須為國家設置或管理", "木棧道必須已開始提供大眾使用", "必須甲的受傷與木棧道的使用具有相當因果關係", "管理機關因已設置警告標示，故不負損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00192', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依據國家賠償法第9條之規定，有關國家賠償義務機關之認定，下列敘述何者錯誤？', '["公務員執行職務行使公權力所生對於人民之國家賠償責任，以該公務員所屬機關為賠償義務機關", "公共設施因設置或管理有欠缺所生之國家賠償責任，以該公共設施之設置或管理機關為賠償義務機關", "委託民間團體或個人管理之公共設施，因設置或管理有欠缺所生之國家賠償責任，以受委託之民間團體 或個人為賠償義務機關", "原賠償義務機關裁撤或改組者，以承受其業務之機關為賠償義務機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00193', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '國家賠償法有關國家賠償之相關規定，下列敘述何者錯誤？', '["國家賠償法所稱之公務員係指依法令從事於公務之人員", "公務員執行職務行使公權力致使國家應負損害賠償責任時，賠償機關於該公務員有故意或重大過失之 情形，得對該公務員求償", "於開放之山域、水域等自然公物，經管理機關、受委託管理之民間團體或個人已就使用該公物為適當之 警告或標示，而人民仍從事冒險或具危險性活動，國家不負損害賠償責任", "國家賠償損害賠償訴訟，適用行政訴訟法之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00194', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '設A不動產經紀業（公司；代表人甲）雇用乙經紀人、丙經紀營業員，經營不動產仲介業務。甲明知A 公司尚未與委託人簽訂委託契約書，即以A公司名義刊登內容不實之銷售廣告，違反不動產經紀業管理 條例第21條規定，主管機關依同條例第29條第1項第1款及第2項規定，處A公司6萬元罰鍰並令其 限期改正。有關於此，下列敘述何者正確？', '["甲依行政罰法第15條第1項規定，並受同一規定罰鍰之處罰", "若該不動產廣告稿係由乙經紀人簽章且以A公司名義刊登，甲不負行政罰責任", "乙若因未簽章不動產廣告稿，因而違反不動產經紀業管理條例相關規定而受懲戒，違反一行為不兩罰原則", "令A公司限期改正與罰鍰同屬行政罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00195', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關規費事項，下列敘述何者正確？', '["申請土地登記謄本應繳納之規費，為規費法所稱之行政規費", "申請鑑界應繳納之土地複丈費，為規費法所稱之使用規費", "申請抵押權設定登記，應繳納權利價值千分之一之登記費；該登記費為規費法所稱之行政規費", "行政機關對逾期繳納規費者，得加徵滯納金；該滯納金之性質為行政罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00196', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '假定甲國的生產可能曲線往右上方擴增，下列何者可能是甲國生產可能性曲線發生變化的原因？', '["貧富差距縮小", "經濟出現停滯", "失業率上升", "生產技術進步"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00197', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '經濟制度是指政府介入人民經濟生活的方式與程度，下列有關「市場經濟制度」的敘述，何者錯誤？', '["政府保障人民的消費自由", "政府尊重市場的價格機能", "政府讓個人依自利做決策", "政府將生產工具收歸國有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
